import { readFile, writeFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";

const projectRoot = fileURLToPath(new URL("../", import.meta.url));
const manifestPath = new URL("../contract-manifest.json", import.meta.url);
const outputPath = new URL("../src/shared/api/generated/constants.ts", import.meta.url);

const manifest = JSON.parse(await readFile(manifestPath, "utf8"));
const lines = [
  "// This file is generated from contract-manifest.json.",
  "// Run `npm run generate:api`; do not edit this file directly.",
  "",
];

const toConstantName = (value) => value
  .replace(/([a-z0-9])([A-Z])/g, "$1_$2")
  .replace(/[^A-Za-z0-9]+/g, "_")
  .replace(/^_+|_+$/g, "")
  .toUpperCase();

const literal = (value) => JSON.stringify(value, null, 2);
const exportConst = (name, value) => {
  lines.push(`export const ${name} = ${literal(value)} as const;`, "");
};

const enumMemberName = (value) => {
  const name = toConstantName(value);
  return /^\d/.test(name) ? `VALUE_${name}` : name;
};

exportConst("CONTRACT_VERSION", manifest.contract_version);
exportConst("FIELD_CONSTRAINTS", manifest.field_constraints);
exportConst("FIELD_DEFAULTS", manifest.field_defaults);
exportConst("STATUS_TRANSITIONS", manifest.status_transitions);

for (const [schemaName, values] of Object.entries(manifest.enums)) {
  const constantName = toConstantName(schemaName);
  const members = Object.fromEntries(values.map((value) => [enumMemberName(value), value]));
  if (Object.keys(members).length !== values.length) {
    throw new Error(`enum member collision in ${schemaName}`);
  }
  exportConst(`${constantName}_VALUES`, values);
  exportConst(constantName, members);
}

for (const [resourceName, transitions] of Object.entries(manifest.status_transitions)) {
  exportConst(`${toConstantName(resourceName)}_STATUS_TRANSITIONS`, transitions);
}

for (const [groupName, limits] of Object.entries(manifest.limits)) {
  for (const [limitName, value] of Object.entries(limits)) {
    exportConst(`${toConstantName(groupName)}_${toConstantName(limitName)}`, value);
  }
}

exportConst("AGENT_DEFAULT_CODE", manifest.agent.default_code);
exportConst("AGENT_IDENTITIES", manifest.agent.identities);
exportConst("AGENT_CAPABILITIES", manifest.agent.capabilities);
exportConst("AUTH_ACCESS_TOKEN_HEADER", manifest.auth.access_token_header);
exportConst("KNOWLEDGE_ACCEPTED_SUFFIXES", manifest.knowledge.accepted_suffixes);
exportConst("KNOWLEDGE_DOCUMENT_ACCEPT", manifest.knowledge.document_accept);
exportConst("KNOWLEDGE_INFLIGHT_STATUSES", manifest.knowledge.inflight_statuses);

await writeFile(outputPath, `${lines.join("\n").trimEnd()}\n`, "utf8");
console.log(`Generated ${outputPath.pathname.replace(projectRoot, "")}`);
